/**
 * @public
 */
export type ThresholdPosition = 'left' | 'right';
/**
 * @public
 */
export interface StaticThreshold {
    value: number;
}
/**
 * @public
 */
export interface StaticRangeThreshold {
    min: number;
    max: number;
}
/**
 * @public
 */
export type DynamicThreshold = {
    value: number;
    date: Date;
}[];
/**
 * @public
 */
export type DynamicRangeThreshold = {
    min: number;
    max: number;
    date: Date;
}[];
/**
 * @public
 */
export type DynamicNumericThreshold = {
    value: number;
    point: number;
}[];
/**
 * @public
 */
export type DynamicNumericRangeThreshold = {
    min: number;
    max: number;
    point: number;
}[];
/**
 * @public
 */
export type ThresholdData = StaticThreshold | StaticRangeThreshold;
/**
 * @public
 */
export interface BaseThresholdConfig {
    /** The unique color picked for this representation in HEX, RGB, Color Token or HSL.*/
    color: string;
    /**
     * Label to be shown in the threshold tooltip.
     * @defaultValue "Threshold"
     */
    label?: string;
    /** Whereas to show the ranges filled or only the strokes */
    strokeOnly?: boolean;
}
/**
 * @public
 */
export type DateThresholdData = ThresholdData | DynamicThreshold | DynamicRangeThreshold;
/** @public */
export type DateThresholdPosition = ThresholdPosition;
/**
 * @public
 */
export interface DateThresholdConfig extends BaseThresholdConfig {
    /** The threshold data to be graphed by the component */
    data: DateThresholdData;
    /** The position of the threshold relative to the chart. */
    position?: DateThresholdPosition;
}
/**
 * @public
 */
export type NumericalThresholdData = ThresholdData | DynamicNumericThreshold | DynamicNumericRangeThreshold;
/**
 * @public
 */
export type NumericalThresholdPosition = ThresholdPosition;
/**
 * @public
 */
export interface NumericalThresholdConfig extends BaseThresholdConfig {
    /** The threshold data to be graphed by the component */
    data: NumericalThresholdData;
    /** The position of the threshold relative to the chart. */
    position?: NumericalThresholdPosition;
}
